function normalizeLocation(v){const x=Number(v?.x),y=Number(v?.y),kind=v?.kind;if(!Number.isInteger(x)||!Number.isInteger(y)||Math.abs(x)>400||Math.abs(y)>400||!(kind==="oasis"||kind==="cropper9"||kind==="cropper15"||/^field(?:[1-9]|1[0-2])$/.test(kind)))return null;const bonuses={};for(const r of ["wood","clay","iron","crop"])if(Number(v.bonuses?.[r])>0)bonuses[r]=Number(v.bonuses[r]);return{x,y,kind,bonuses,occupied:Boolean(v.occupied),rawClass:String(v.rawClass||"").slice(0,500),rawTitle:String(v.rawTitle||"").slice(0,1000)}}
