const alliances=(()=>{const a={};for(const v of DATA){if(!v.alliance)continue;const x=a[v.alliance]??={tag:v.alliance,pop:0,villages:0,players:new Set(),sx:0,sy:0};x.pop+=v.population||0;x.villages++;x.players.add(v.playerId);x.sx+=v.x;x.sy+=v.y}return Object.values(a).map(x=>({...x,players:x.players.size,cx:x.sx/x.villages,cy:x.sy/x.villages})).sort((a,b)=>b.pop-a.pop)})();
const players=(()=>{const p={};for(const v of DATA){const x=p[v.playerId]??={id:v.playerId,name:v.player,alliance:v.alliance,pop:0,villages:[]};x.pop+=v.population||0;x.villages.push(v)}return Object.values(p).sort((a,b)=>b.pop-a.pop)})();
