function applyLanguage(){document.documentElement.lang=state.lang;document.querySelectorAll("[data-t]").forEach(e=>e.textContent=t(e.dataset.t));document.querySelectorAll("[data-t-placeholder]").forEach(e=>e.placeholder=t(e.dataset.tPlaceholder));document.querySelectorAll("[data-t-aria]").forEach(e=>e.setAttribute("aria-label",t(e.dataset.tAria)));$("languageTop").value=state.lang;$("languageInput").value=state.lang;const stamp=META.updatedAt?new Date(META.updatedAt):null,hours=stamp?Math.max(0,Math.floor((Date.now()-stamp)/36e5)):null;$("dataAge").textContent=stamp?(state.lang==="hr"?`Snimka od ${stamp.toLocaleDateString("hr-HR")} · ${hours} h stara`:`Snapshot ${stamp.toLocaleDateString("en-GB")} · ${hours}h old`):"—";renderView()}
function pageHead(title,sub,actions=""){return `<div class="page-head"><div><p class="eyebrow">M HQ · TS4</p><h1>${t(title)}</h1><p>${t(sub)}</p></div><div class="button-row">${actions}</div></div>`}
function nav(view){state.view=view;location.hash=view;document.querySelectorAll("#mainNav button").forEach(b=>b.classList.toggle("active",b.dataset.view===view));document.querySelectorAll(".view").forEach(v=>v.classList.toggle("active",v.id===view));$("sidebar").classList.remove("open");renderView();window.scrollTo(0,0);requestAnimationFrame(()=>window.scrollTo(0,0))}
